import React, { useState } from 'react';
import BarcodeScanner from './components/BarcodeScanner';
import Cart from './components/Cart';
import Checkout from './components/Checkout';
import BillSuccess from './components/BillSuccess';
import Toast from './components/Toast';
import { productService, billService } from './services/api';
import config from './config';
import './App.css';

/**
 * FIXED Main App Component
 * - Toast notifications instead of alert()
 * - Uses backend calculations only
 * - Proper error handling
 */
function App() {
  const [cartItems, setCartItems] = useState([]);
  const [showCheckout, setShowCheckout] = useState(false);
  const [generatedBill, setGeneratedBill] = useState(null);
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState(null);

  /**
   * Show toast notification (replaces alert())
   */
  const showToast = (message, type = 'info') => {
    setToast({ message, type });
  };

  const closeToast = () => {
    setToast(null);
  };

  /**
   * Handle barcode scan
   */
  const handleBarcodeScan = async (productId) => {
    try {
      setLoading(true);

      const response = await productService.getProductBySKU(productId);

      if (!response.success) {
        showToast(response.message || 'Product not found', 'error');
        return;
      }

      const product = response.data;

      const existingItemIndex = cartItems.findIndex(
        item => item.productId === product.productId
      );

      if (existingItemIndex !== -1) {
        const updatedItems = [...cartItems];
        updatedItems[existingItemIndex].qty += 1;
        setCartItems(updatedItems);
        showToast(`${product.name} quantity increased`, 'success');
      } else {
        const cartItem = {
          productId: product.productId,
          name: product.name,
          price: product.price,
          qty: 1
        };
        setCartItems([...cartItems, cartItem]);
        showToast(`${product.name} added to cart`, 'success');
      }

      if (response.warning) {
        showToast(response.warning, 'warning');
      }

    } catch (error) {
      console.error('Error scanning barcode:', error);
      showToast(error.message || 'Failed to fetch product', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleScanError = (error) => {
    showToast(error, 'error');
  };

  const handleUpdateQuantity = (index, newQty) => {
    if (newQty < 1) return;
    const updatedItems = [...cartItems];
    updatedItems[index].qty = newQty;
    setCartItems(updatedItems);
  };

  const handleRemoveItem = (index) => {
    const updatedItems = cartItems.filter((_, i) => i !== index);
    setCartItems(updatedItems);
    showToast('Item removed from cart', 'info');
  };

  const handleCheckout = () => {
    if (cartItems.length === 0) {
      showToast('Cart is empty', 'warning');
      return;
    }
    setShowCheckout(true);
  };

  const handleCheckoutCancel = () => {
    setShowCheckout(false);
  };

  /**
   * CRITICAL: Use backend calculations only
   */
  const handleCheckoutConfirm = async (totals) => {
    try {
      setLoading(true);

      const billData = {
        items: cartItems,
        discountPercent: totals.discountPercent
      };

      const response = await billService.createBill(billData);

      if (!response.success) {
        throw new Error(response.message || 'Failed to create bill');
      }

      // Use backend-calculated bill data
      setGeneratedBill(response.data);
      setCartItems([]);
      setShowCheckout(false);

      showToast('Bill generated successfully!', 'success');

    } catch (error) {
      console.error('Error creating bill:', error);
      showToast(error.message || 'Failed to generate bill', 'error');
      throw error;
    } finally {
      setLoading(false);
    }
  };

  const handleNewBill = () => {
    setGeneratedBill(null);
    setCartItems([]);
    showToast('Ready for new bill', 'info');
  };

  if (generatedBill) {
    return (
      <div className="app">
        <BillSuccess 
          bill={generatedBill}
          onNewBill={handleNewBill}
        />
        {toast && (
          <Toast 
            message={toast.message}
            type={toast.type}
            onClose={closeToast}
          />
        )}
      </div>
    );
  }

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-content">
          <h1 className="app-title">
            <span className="title-icon">🏪</span>
            {config.STORE_NAME}
          </h1>
          <p className="app-subtitle">Smart Billing System</p>
        </div>
      </header>

      <main className="app-main">
        <section className="scanner-section">
          <BarcodeScanner 
            onScan={handleBarcodeScan}
            onError={handleScanError}
          />
        </section>

        <section className="cart-section">
          <Cart 
            items={cartItems}
            onUpdateQuantity={handleUpdateQuantity}
            onRemoveItem={handleRemoveItem}
            onCheckout={handleCheckout}
          />
        </section>
      </main>

      {showCheckout && (
        <Checkout 
          items={cartItems}
          onConfirm={handleCheckoutConfirm}
          onCancel={handleCheckoutCancel}
        />
      )}

      {loading && (
        <div className="loading-overlay">
          <div className="loading-spinner"></div>
          <p>Processing...</p>
        </div>
      )}

      {toast && (
        <Toast 
          message={toast.message}
          type={toast.type}
          onClose={closeToast}
        />
      )}

      <footer className="app-footer">
        <p>Powered by Smart Billing System v1.0 - FIXED</p>
      </footer>
    </div>
  );
}

export default App;
